public ListNode mergeTwoLists(ListNode list1, ListNode list2) {
        ListNode mergedList = new ListNode(-1);
        ListNode dummy = mergedList;

        while (list1 != null && list2 != null) {

            if (list1.val <= list2.val) {
                dummy.next = list1;
                list1 = list1.next;
            } else {
                dummy.next = list2;
                list2 = list2.next;
            }

            dummy = dummy.next;
        }

        // dummy.next = (list1 != null) ? list1 : list2;

        if (list1 != null) {
            dummy.next = list1;
        } else {
            dummy.next = list2;
        }

        return mergedList.next;

    }

public int removeDuplicates(int[] nums) {

        /**
         * walk through array if seen number is -1, assign seen number to the
         * first number in array if seen number is == to current number, remove
         * current number, increment k
         */
        if (nums.length == 0) {
            return 0;
        }
        int i = 0;
        for (int j = 1; j < nums.length; j++) {
            if (nums[j] != nums[i]) {
                i++;
                nums[i] = nums[j];
            }
        }
        return i + 1;
    }

