public TreeNode insert(Integer[] node, int index) {
        if (index >= node.length || node[index] == null) {
            return null;
        }

        TreeNode root = new TreeNode(node[index]);
        root.left = insert(node, 2 * index + 1);
        root.right = insert(node, 2 * index + 2);
        return root;
    }

