private int getSum(TreeNode root) {
        int sum = 0;

        if (root == null) {
            return 0;
        }

        if (root.left != null && root.left.left == null && root.left.right == null) {
            sum += root.left.val;
        }

        sum += getSum(root.left);
        sum += getSum(root.right);

        return sum;
    }

public int sumOfLeftLeaves(TreeNode root) {
        return getSum(root);
    }

