public int sumOddLengthSubarrays(int[] arr) {
        int sum = 0;
        int n = arr.length;
        if (arr.length == 0) {
            return sum;
        }

        for (int i = 0; i < n; i++) {
            int end = i + 1;
            int start = n - i;
            int total = start * end;
            int odd = total / 2;

            if (total % 2 == 1) {
                odd++;
            }

            sum += odd * arr[i];
        }

        return sum;
    }

