public int maxDistance(int[] colors) {
        int max = 0;

        for (int i = 0; i < colors.length; i++) {
            int housePointer = colors.length - 1;
            int maxDistance = 0;

            while (housePointer != i) {
                if (colors[i] != colors[housePointer] && housePointer == colors.length) {
                    max = housePointer - i;
                    break;
                } else if (colors[i] != colors[housePointer]) {
                    maxDistance = housePointer - i;

                    if (maxDistance > max) {
                        max = maxDistance;
                    }
                }

                housePointer--;

            }

            if (max == colors.length - 1) {
                break;
            }

        }

        return max;
    }

public boolean checkValid(int[][] matrix) {

        int n = matrix.length;

        // Check each row
        for (int[] row : matrix) {
            HashSet<Integer> set = new HashSet<>();
            for (int num : row) {
                set.add(num);
            }
            if (set.size() != n)
                return false; // Row does not contain all numbers
        }

        // Check each column
        for (int col = 0; col < n; col++) {
            HashSet<Integer> set = new HashSet<>();
            for (int row = 0; row < n; row++) {
                set.add(matrix[row][col]);
            }
            if (set.size() != n)
                return false; // Column does not contain all numbers
        }

        return true; // All rows and columns are valid
    }

