            // ans[i] | (ans[i] + 1) == nums[i]
            ans[i] = -1;
            int value = nums.get(i);
            for (int j = 0; j < value; j++) {
                if ((j | (j + 1)) == value) {
                    ans[i] = j;
                    break;
                }

            }

        }

        return ans;
    }

public int maxFreqSum(String s) {
        Map<Character, Integer> vowelMap = new HashMap<>();
        Map<Character, Integer> consonantsMap = new HashMap<>();
        int vowel = 0;
        int consonants = 0;

        for (int i = 0; i < s.length(); i++) {
            if ("aeiou".indexOf(s.charAt(i)) >= 0) {
                vowelMap.put(s.charAt(i), vowelMap.getOrDefault(s.charAt(i), 0) + 1);
            } else {
                consonantsMap.put(s.charAt(i), consonantsMap.getOrDefault(s.charAt(i), 0) + 1);
            }
        }

        for (int value : vowelMap.values()) {
            if (value > vowel) {
                vowel = value;
            }
        }

        for (int value : consonantsMap.values()) {
            if (value > consonants) {
                consonants = value;
            }
        }

        return vowel + consonants;
    }

private boolean leftAscending(int[] nums, int p) {

        for (int i = 0; i < p; i++) {
            if (nums[i] >= nums[i + 1]) {
                return false;
            }
        }

        return true;
    }

private boolean descending(int[] nums, int p, int q) {

        for (int i = p; i < q; i++) {
            if (nums[i] <= nums[i + 1]) {
                return false;
            }
        }

        return true;
    }

private boolean rightAscending(int[] nums, int q) {

        for (int i = q; i < nums.length - 1; i++) {
            if (nums[i] >= nums[i + 1]) {
                return false;
            }
        }

        return true;
    }

public boolean isTrionic(int[] nums) {
        int p = 1;
        int q = p + 1;
        boolean satifies = false;
        // 0 < p < q < n-1

        while (p < q && q < nums.length - 1) {

            // check first
            if (!leftAscending(nums, p)) {
                // move p pointer
                p++;
                continue;
            }

            // check middle
            if (!descending(nums, p, q)) {
                // move p and q pointer
                p++;
                q++;
                continue;
            }

            // check last

            if (!rightAscending(nums, q)) {
                // move q pointer
                q++;
                continue;
            }
            satifies = true;
            break;
        }

        return satifies;
    }

public int longestBalanced(String s) {

        int longest = 0, length = 0, distinct = 0, maxFreq = 0;

        if (s.length() == 0) {
            return longest;
        } else if (s.length() == 1) {
            return 1;
        }

        for (int i = 0; i < s.length(); i++) {
            int[] count = new int[26];
            for (int j = i; j < s.length(); j++) {

                if (count[s.charAt(j) - 'a'] == 0) {
                    distinct++;
                    count[s.charAt(j) - 'a']++;

                } else {
                    count[s.charAt(j) - 'a']++;

                }
                maxFreq = Math.max(maxFreq, count[s.charAt(j) - 'a']);
                length++;
                if (length == distinct * maxFreq) {
                    longest = Math.max(longest, length);
                }
            }
            length = 0;
            distinct = 0;
            maxFreq = 0;
        }

        return longest;
    }

public int reverse(int x) {

        Queue<Integer> reversed = new LinkedList<>();

        int result = 0;
        while (x != 0) {
            int remainder = x % 10;

            x /= 10;
            reversed.add(remainder);
        }

        if (reversed.size() > 10) {

            return 0;
        }

        if (reversed.isEmpty()) {
            return 0;
        }
        int head = reversed.peek();

        while (!reversed.isEmpty()) {
            result = result * 10 + reversed.poll();
        }

        int checkHead = result;

        while (Math.abs(checkHead) >= 10) {
            checkHead /= 10;
        }

        if ((head != checkHead && head != 0) || result < Integer.MIN_VALUE || result > Integer.MAX_VALUE) {
            return 0;
        }

        return result;
    }

public void inorder(TreeNode root, List<Integer> array) {
        if (root == null)
            return;
        inorder(root.left, array);
        array.add(root.val);
        inorder(root.right, array);
    }

public List<Integer> createSortedArray(TreeNode root) {
        List<Integer> result = new ArrayList<>();
        inorder(root, result);

        return result;
    }

public TreeNode insert(int[] sorted, int left, int right) {
        if (left > right)
            return null;

        int mid = left + (right - left) / 2;

        TreeNode root = new TreeNode(sorted[mid]);

        root.left = insert(sorted, left, mid - 1);
        root.right = insert(sorted, mid + 1, right);

        return root;
    }

public TreeNode buildBST(int[] arr) {
        return insert(arr, 0, arr.length - 1);
    }

public TreeNode balanceBST(TreeNode root) {
        TreeNode balanced;
        List<Integer> sorted = new ArrayList<>();

        // perform inorder traversal to create sorted array
        sorted = createSortedArray(root);
        int[] sortedArray = new int[sorted.size()];

        for (int i = 0; i < sorted.size(); i++) {
            sortedArray[i] = sorted.get(i);
        }
        // reconstruct balanced binary search tree
        balanced = buildBST(sortedArray);
        return balanced;
    }

public int longestBalanced(int[] nums) {
        Set<Integer> evenNumbers = new HashSet<>();
        Set<Integer> oddNumbers = new HashSet<>();
        int longest = 0, even = 0, odd = 0, length = 0;

        if (nums.length == 1) {
            return longest;
        }
        // x % 2 = 0 -> even

        for (int i = 0; i < nums.length; i++) {

            for (int j = i; j < nums.length; j++) {
                if (nums[j] % 2 == 0 && !evenNumbers.contains(nums[j])) {
                    even++;
                    evenNumbers.add(nums[j]);
                } else if (nums[j] % 2 == 1 && !oddNumbers.contains(nums[j])) {
                    odd++;
                    oddNumbers.add(nums[j]);
                }
                length++;

                if (even == odd) {
                    longest = Math.max(longest, length);
                }
            }

            length = 0;
            even = 0;
            odd = 0;
            evenNumbers.clear();
            oddNumbers.clear();
        }
        return longest;
    }
